const item = $('Webhook_CurationSubmit').first().json;
const cfg = $('Set_Config_Persistencia').first().json;
const batch_id = String(item.batch_id || '');
const user_notes = String(item.user_notes || '');
const docs = Array.isArray(item.docs) ? item.docs : [];
if (!docs.length) throw new Error('docs vacío');

return docs.map((d, idx) => {
  const b64 = String(d.original_base64 || '');
  if (!b64) throw new Error(`docs[${idx}].original_base64 vacío`);
  const filename = String(d.filename || `doc_${idx}.bin`);
  const mime = String(d.mime || 'application/octet-stream');
  const rows = Array.isArray(d.rows) ? d.rows : [];
  return {
    json: {
      batch_id,
      user_notes,
      doc_index: idx,
      filename,
      mime,
      rows,
      drive_folder_id: cfg.drive_folder_id,
      google_sheet_id: cfg.google_sheet_id,
    },
    binary: {
      image: {
        data: b64,
        fileName: filename,
        mimeType: mime,
      },
    },
  };
});

const up = $json;
const driveId = up.id;
const driveLink = up.webViewLink || up.webContentLink || '';
const filename = String($('Code_Split_Docs_To_Items').item.json.filename || '');
const batch_id = String($('Code_Split_Docs_To_Items').item.json.batch_id || '');
const rows = $('Code_Split_Docs_To_Items').item.json.rows || [];
const out = [];

for (const row of rows) {
  out.push({
    json: {
      ...row,
      Batch_Id: batch_id,
      Source_File: filename,
      Drive_File_Id: driveId,
      Drive_Link: driveLink,
    },
  });
}

return out.length ? out : [{ json: { Batch_Id: batch_id, Source_File: filename, Drive_File_Id: driveId, Drive_Link: driveLink, Note: 'sin filas' } }];

const root = $('Webhook_CurationSubmit').first().json;
const batch_id = String(root.batch_id || '');
const task_id = String(root.task_id || '');
const user_notes = String(root.user_notes || '').trim();
const docCount = Array.isArray(root.docs) ? root.docs.length : 0;
const flat = Array.isArray(root.flat_rows) ? root.flat_rows : [];
const rowsCount = flat.length || $input.all().length;

function esc(s) {
  return String(s ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

const cols = ['Comprobante', 'Nombre', 'Detalle', 'Precio', 'F.Emision'];
const slice = flat.slice(0, 10);
let tableHtml = '';
if (slice.length) {
  const head = '<tr>' + cols.map((c) => '<th style="text-align:left;padding:6px;border:1px solid #ccc">' + esc(c) + '</th>').join('') + '</tr>';
  const body = slice.map((r) => '<tr>' + cols.map((c) => '<td style="padding:6px;border:1px solid #eee">' + esc((r[c] ?? '').toString().slice(0, 120)) + '</td>').join('') + '</tr>').join('');
  tableHtml = '<table style="border-collapse:collapse;margin-top:12px;font-size:13px">' + head + body + '</table>';
} else {
  tableHtml = '<p><em>No hubo flat_rows en el payload; revisá el nodo Sheets.</em></p>';
}

const email_html = '<html><body style="font-family:system-ui,sans-serif;max-width:720px;line-height:1.5">' +
  '<h2 style="color:#0f172a">Rendiciones — lote confirmado en curación</h2>' +
  '<p>Estimado/a: se completó la <strong>validación humana</strong> de la extracción y se ejecutaron las acciones siguientes:</p>' +
  '<ul>' +
  '<li><strong>Archivos</strong> guardados en Google Drive (carpeta Rendiciones aprobadas).</li>' +
  '<li><strong>Datos contables</strong> agregados en Google Sheets, hoja <strong>Rendiciones</strong> (' + rowsCount + ' fila(s)).</li>' +
  '<li><strong>Documentos</strong> en el lote: ' + docCount + '.</li>' +
  '</ul>' +
  '<p><strong>Batch ID:</strong> ' + esc(batch_id) + '<br/>' +
  '<strong>ID tarea:</strong> ' + esc(task_id) + '</p>' +
  (user_notes ? '<p><strong>Notas del envío:</strong> ' + esc(user_notes) + '</p>' : '') +
  '<h3 style="margin-top:20px">Vista rápida de líneas registradas</h3>' + tableHtml +
  (flat.length > 10 ? '<p style="color:#64748b;font-size:13px">…y más filas en la planilla.</p>' : '') +
  '<p style="margin-top:24px;color:#64748b;font-size:12px">Mensaje automático (Autodoc v2).</p>' +
  '</body></html>';

return [{ json: { batch_id, task_id, doc_count: docCount, rows_count: rowsCount, email_html } }];
